/*\n  # Optimize Remaining RLS Policies - Part 2\n  \n  ## Tables Optimized (Part 2 of 4)\n  - user_resumes (5 policies)\n  - realistic_interview_sessions (3 policies)\n  - realistic_interview_responses (3 policies)\n  - realistic_interview_followups (2 policies)\n  - realistic_interview_code_reviews (2 policies)\n  - smart_interview_sessions (3 policies)\n  - smart_interview_questions (1 policy)\n  - smart_interview_responses (3 policies)\n  - code_execution_results (2 policies)\n  - code_logic_review_questions (2 policies)\n  - code_logic_review_responses (2 policies)\n  - ai_project_suggestions (4 policies)\n  - interview_session_backups (4 policies)\n*/\n\n-- ============================================================================\n-- USER_RESUMES TABLE\n-- ============================================================================\n\nDROP POLICY IF EXISTS "Users can view own resumes" ON public.user_resumes;
\nDROP POLICY IF EXISTS "Users can upload own resumes" ON public.user_resumes;
\nDROP POLICY IF EXISTS "Users can update own resumes" ON public.user_resumes;
\nDROP POLICY IF EXISTS "Users can delete own resumes" ON public.user_resumes;
\nDROP POLICY IF EXISTS "Admins can view all resumes" ON public.user_resumes;
\n\nCREATE POLICY "Users can view own resumes" ON public.user_resumes\n  FOR SELECT TO authenticated\n  USING ((SELECT auth.uid()) = user_id);
\n\nCREATE POLICY "Users can upload own resumes" ON public.user_resumes\n  FOR INSERT TO authenticated\n  WITH CHECK ((SELECT auth.uid()) = user_id);
\n\nCREATE POLICY "Users can update own resumes" ON public.user_resumes\n  FOR UPDATE TO authenticated\n  USING ((SELECT auth.uid()) = user_id)\n  WITH CHECK ((SELECT auth.uid()) = user_id);
\n\nCREATE POLICY "Users can delete own resumes" ON public.user_resumes\n  FOR DELETE TO authenticated\n  USING ((SELECT auth.uid()) = user_id);
\n\nCREATE POLICY "Admins can view all resumes" ON public.user_resumes\n  FOR SELECT TO authenticated\n  USING (is_admin((SELECT auth.uid())));
\n\n-- ============================================================================\n-- REALISTIC_INTERVIEW_SESSIONS TABLE\n-- ============================================================================\n\nDROP POLICY IF EXISTS "Users can view own interview sessions" ON public.realistic_interview_sessions;
\nDROP POLICY IF EXISTS "Users can create own interview sessions" ON public.realistic_interview_sessions;
\nDROP POLICY IF EXISTS "Users can update own interview sessions" ON public.realistic_interview_sessions;
\n\nCREATE POLICY "Users can view own interview sessions" ON public.realistic_interview_sessions\n  FOR SELECT TO authenticated\n  USING ((SELECT auth.uid()) = user_id);
\n\nCREATE POLICY "Users can create own interview sessions" ON public.realistic_interview_sessions\n  FOR INSERT TO authenticated\n  WITH CHECK ((SELECT auth.uid()) = user_id);
\n\nCREATE POLICY "Users can update own interview sessions" ON public.realistic_interview_sessions\n  FOR UPDATE TO authenticated\n  USING ((SELECT auth.uid()) = user_id)\n  WITH CHECK ((SELECT auth.uid()) = user_id);
\n\n-- ============================================================================\n-- REALISTIC_INTERVIEW_RESPONSES TABLE\n-- ============================================================================\n\nDROP POLICY IF EXISTS "Users can view own interview responses" ON public.realistic_interview_responses;
\nDROP POLICY IF EXISTS "Users can create own interview responses" ON public.realistic_interview_responses;
\nDROP POLICY IF EXISTS "Users can update own interview responses" ON public.realistic_interview_responses;
\n\nCREATE POLICY "Users can view own interview responses" ON public.realistic_interview_responses\n  FOR SELECT TO authenticated\n  USING (EXISTS (\n    SELECT 1 FROM public.realistic_interview_sessions\n    WHERE realistic_interview_sessions.id = realistic_interview_responses.session_id\n    AND realistic_interview_sessions.user_id = (SELECT auth.uid())\n  ));
\n\nCREATE POLICY "Users can create own interview responses" ON public.realistic_interview_responses\n  FOR INSERT TO authenticated\n  WITH CHECK (EXISTS (\n    SELECT 1 FROM public.realistic_interview_sessions\n    WHERE realistic_interview_sessions.id = realistic_interview_responses.session_id\n    AND realistic_interview_sessions.user_id = (SELECT auth.uid())\n  ));
\n\nCREATE POLICY "Users can update own interview responses" ON public.realistic_interview_responses\n  FOR UPDATE TO authenticated\n  USING (EXISTS (\n    SELECT 1 FROM public.realistic_interview_sessions\n    WHERE realistic_interview_sessions.id = realistic_interview_responses.session_id\n    AND realistic_interview_sessions.user_id = (SELECT auth.uid())\n  ))\n  WITH CHECK (EXISTS (\n    SELECT 1 FROM public.realistic_interview_sessions\n    WHERE realistic_interview_sessions.id = realistic_interview_responses.session_id\n    AND realistic_interview_sessions.user_id = (SELECT auth.uid())\n  ));
\n\n-- ============================================================================\n-- REALISTIC_INTERVIEW_FOLLOWUPS TABLE\n-- ============================================================================\n\nDROP POLICY IF EXISTS "Users can view own interview followups" ON public.realistic_interview_followups;
\nDROP POLICY IF EXISTS "Users can create own interview followups" ON public.realistic_interview_followups;
\n\nCREATE POLICY "Users can view own interview followups" ON public.realistic_interview_followups\n  FOR SELECT TO authenticated\n  USING (EXISTS (\n    SELECT 1 FROM public.realistic_interview_sessions\n    WHERE realistic_interview_sessions.id = realistic_interview_followups.session_id\n    AND realistic_interview_sessions.user_id = (SELECT auth.uid())\n  ));
\n\nCREATE POLICY "Users can create own interview followups" ON public.realistic_interview_followups\n  FOR INSERT TO authenticated\n  WITH CHECK (EXISTS (\n    SELECT 1 FROM public.realistic_interview_sessions\n    WHERE realistic_interview_sessions.id = realistic_interview_followups.session_id\n    AND realistic_interview_sessions.user_id = (SELECT auth.uid())\n  ));
\n\n-- ============================================================================\n-- REALISTIC_INTERVIEW_CODE_REVIEWS TABLE\n-- ============================================================================\n\nDROP POLICY IF EXISTS "Users can view own code reviews" ON public.realistic_interview_code_reviews;
\nDROP POLICY IF EXISTS "Users can create own code reviews" ON public.realistic_interview_code_reviews;
\n\nCREATE POLICY "Users can view own code reviews" ON public.realistic_interview_code_reviews\n  FOR SELECT TO authenticated\n  USING (EXISTS (\n    SELECT 1 FROM public.realistic_interview_sessions\n    WHERE realistic_interview_sessions.id = realistic_interview_code_reviews.session_id\n    AND realistic_interview_sessions.user_id = (SELECT auth.uid())\n  ));
\n\nCREATE POLICY "Users can create own code reviews" ON public.realistic_interview_code_reviews\n  FOR INSERT TO authenticated\n  WITH CHECK (EXISTS (\n    SELECT 1 FROM public.realistic_interview_sessions\n    WHERE realistic_interview_sessions.id = realistic_interview_code_reviews.session_id\n    AND realistic_interview_sessions.user_id = (SELECT auth.uid())\n  ));
\n\n-- ============================================================================\n-- SMART_INTERVIEW_SESSIONS TABLE\n-- ============================================================================\n\nDROP POLICY IF EXISTS "Users can view own sessions" ON public.smart_interview_sessions;
\nDROP POLICY IF EXISTS "Users can create own sessions" ON public.smart_interview_sessions;
\nDROP POLICY IF EXISTS "Users can update own sessions" ON public.smart_interview_sessions;
\n\nCREATE POLICY "Users can view own sessions" ON public.smart_interview_sessions\n  FOR SELECT TO authenticated\n  USING ((SELECT auth.uid()) = user_id);
\n\nCREATE POLICY "Users can create own sessions" ON public.smart_interview_sessions\n  FOR INSERT TO authenticated\n  WITH CHECK ((SELECT auth.uid()) = user_id);
\n\nCREATE POLICY "Users can update own sessions" ON public.smart_interview_sessions\n  FOR UPDATE TO authenticated\n  USING ((SELECT auth.uid()) = user_id)\n  WITH CHECK ((SELECT auth.uid()) = user_id);
\n\n-- ============================================================================\n-- SMART_INTERVIEW_QUESTIONS TABLE\n-- ============================================================================\n\nDROP POLICY IF EXISTS "Admins can manage questions" ON public.smart_interview_questions;
\n\nCREATE POLICY "Admins can manage questions" ON public.smart_interview_questions\n  FOR ALL TO authenticated\n  USING (is_admin((SELECT auth.uid())))\n  WITH CHECK (is_admin((SELECT auth.uid())));
\n\n-- ============================================================================\n-- SMART_INTERVIEW_RESPONSES TABLE\n-- ============================================================================\n\nDROP POLICY IF EXISTS "Users can view own responses" ON public.smart_interview_responses;
\nDROP POLICY IF EXISTS "Users can create own responses" ON public.smart_interview_responses;
\nDROP POLICY IF EXISTS "Users can update own responses" ON public.smart_interview_responses;
\n\nCREATE POLICY "Users can view own responses" ON public.smart_interview_responses\n  FOR SELECT TO authenticated\n  USING (EXISTS (\n    SELECT 1 FROM public.smart_interview_sessions\n    WHERE smart_interview_sessions.id = smart_interview_responses.session_id\n    AND smart_interview_sessions.user_id = (SELECT auth.uid())\n  ));
\n\nCREATE POLICY "Users can create own responses" ON public.smart_interview_responses\n  FOR INSERT TO authenticated\n  WITH CHECK (EXISTS (\n    SELECT 1 FROM public.smart_interview_sessions\n    WHERE smart_interview_sessions.id = smart_interview_responses.session_id\n    AND smart_interview_sessions.user_id = (SELECT auth.uid())\n  ));
\n\nCREATE POLICY "Users can update own responses" ON public.smart_interview_responses\n  FOR UPDATE TO authenticated\n  USING (EXISTS (\n    SELECT 1 FROM public.smart_interview_sessions\n    WHERE smart_interview_sessions.id = smart_interview_responses.session_id\n    AND smart_interview_sessions.user_id = (SELECT auth.uid())\n  ))\n  WITH CHECK (EXISTS (\n    SELECT 1 FROM public.smart_interview_sessions\n    WHERE smart_interview_sessions.id = smart_interview_responses.session_id\n    AND smart_interview_sessions.user_id = (SELECT auth.uid())\n  ));
\n\n-- ============================================================================\n-- CODE_EXECUTION_RESULTS TABLE\n-- ============================================================================\n\nDROP POLICY IF EXISTS "Users can view own code execution results" ON public.code_execution_results;
\nDROP POLICY IF EXISTS "Users can create own code execution results" ON public.code_execution_results;
\n\nCREATE POLICY "Users can view own code execution results" ON public.code_execution_results\n  FOR SELECT TO authenticated\n  USING (EXISTS (\n    SELECT 1 FROM public.smart_interview_responses sir\n    WHERE sir.id = code_execution_results.response_id\n    AND EXISTS (\n      SELECT 1 FROM public.smart_interview_sessions sis\n      WHERE sis.id = sir.session_id\n      AND sis.user_id = (SELECT auth.uid())\n    )\n  ));
\n\nCREATE POLICY "Users can create own code execution results" ON public.code_execution_results\n  FOR INSERT TO authenticated\n  WITH CHECK (EXISTS (\n    SELECT 1 FROM public.smart_interview_responses sir\n    WHERE sir.id = code_execution_results.response_id\n    AND EXISTS (\n      SELECT 1 FROM public.smart_interview_sessions sis\n      WHERE sis.id = sir.session_id\n      AND sis.user_id = (SELECT auth.uid())\n    )\n  ));
\n\n-- ============================================================================\n-- CODE_LOGIC_REVIEW_QUESTIONS TABLE\n-- ============================================================================\n\nDROP POLICY IF EXISTS "Users can view own review questions" ON public.code_logic_review_questions;
\nDROP POLICY IF EXISTS "System can create review questions" ON public.code_logic_review_questions;
\n\nCREATE POLICY "Users can view own review questions" ON public.code_logic_review_questions\n  FOR SELECT TO authenticated\n  USING (EXISTS (\n    SELECT 1 FROM public.smart_interview_responses sir\n    WHERE sir.id = code_logic_review_questions.response_id\n    AND EXISTS (\n      SELECT 1 FROM public.smart_interview_sessions sis\n      WHERE sis.id = sir.session_id\n      AND sis.user_id = (SELECT auth.uid())\n    )\n  ));
\n\nCREATE POLICY "System can create review questions" ON public.code_logic_review_questions\n  FOR INSERT TO authenticated\n  WITH CHECK (true);
\n\n-- ============================================================================\n-- CODE_LOGIC_REVIEW_RESPONSES TABLE\n-- ============================================================================\n\nDROP POLICY IF EXISTS "Users can view own review responses" ON public.code_logic_review_responses;
\nDROP POLICY IF EXISTS "Users can create own review responses" ON public.code_logic_review_responses;
\n\nCREATE POLICY "Users can view own review responses" ON public.code_logic_review_responses\n  FOR SELECT TO authenticated\n  USING (EXISTS (\n    SELECT 1 FROM public.code_logic_review_questions clrq\n    WHERE clrq.id = code_logic_review_responses.review_question_id\n    AND EXISTS (\n      SELECT 1 FROM public.smart_interview_responses sir\n      WHERE sir.id = clrq.response_id\n      AND EXISTS (\n        SELECT 1 FROM public.smart_interview_sessions sis\n        WHERE sis.id = sir.session_id\n        AND sis.user_id = (SELECT auth.uid())\n      )\n    )\n  ));
\n\nCREATE POLICY "Users can create own review responses" ON public.code_logic_review_responses\n  FOR INSERT TO authenticated\n  WITH CHECK (EXISTS (\n    SELECT 1 FROM public.code_logic_review_questions clrq\n    WHERE clrq.id = code_logic_review_responses.review_question_id\n    AND EXISTS (\n      SELECT 1 FROM public.smart_interview_responses sir\n      WHERE sir.id = clrq.response_id\n      AND EXISTS (\n        SELECT 1 FROM public.smart_interview_sessions sis\n        WHERE sis.id = sir.session_id\n        AND sis.user_id = (SELECT auth.uid())\n      )\n    )\n  ));
\n\n-- ============================================================================\n-- AI_PROJECT_SUGGESTIONS TABLE\n-- ============================================================================\n\nDROP POLICY IF EXISTS "Users can view own project suggestions" ON public.ai_project_suggestions;
\nDROP POLICY IF EXISTS "Users can create own project suggestions" ON public.ai_project_suggestions;
\nDROP POLICY IF EXISTS "Users can update own project suggestions" ON public.ai_project_suggestions;
\nDROP POLICY IF EXISTS "Users can delete own project suggestions" ON public.ai_project_suggestions;
\n\nCREATE POLICY "Users can view own project suggestions" ON public.ai_project_suggestions\n  FOR SELECT TO authenticated\n  USING ((SELECT auth.uid()) = user_id);
\n\nCREATE POLICY "Users can create own project suggestions" ON public.ai_project_suggestions\n  FOR INSERT TO authenticated\n  WITH CHECK ((SELECT auth.uid()) = user_id);
\n\nCREATE POLICY "Users can update own project suggestions" ON public.ai_project_suggestions\n  FOR UPDATE TO authenticated\n  USING ((SELECT auth.uid()) = user_id)\n  WITH CHECK ((SELECT auth.uid()) = user_id);
\n\nCREATE POLICY "Users can delete own project suggestions" ON public.ai_project_suggestions\n  FOR DELETE TO authenticated\n  USING ((SELECT auth.uid()) = user_id);
\n\n-- ============================================================================\n-- INTERVIEW_SESSION_BACKUPS TABLE\n-- ============================================================================\n\nDROP POLICY IF EXISTS "Users can view own session backups" ON public.interview_session_backups;
\nDROP POLICY IF EXISTS "Users can create own session backups" ON public.interview_session_backups;
\nDROP POLICY IF EXISTS "Users can update own session backups" ON public.interview_session_backups;
\nDROP POLICY IF EXISTS "Users can delete own session backups" ON public.interview_session_backups;
\n\nCREATE POLICY "Users can view own session backups" ON public.interview_session_backups\n  FOR SELECT TO authenticated\n  USING ((SELECT auth.uid()) = user_id);
\n\nCREATE POLICY "Users can create own session backups" ON public.interview_session_backups\n  FOR INSERT TO authenticated\n  WITH CHECK ((SELECT auth.uid()) = user_id);
\n\nCREATE POLICY "Users can update own session backups" ON public.interview_session_backups\n  FOR UPDATE TO authenticated\n  USING ((SELECT auth.uid()) = user_id)\n  WITH CHECK ((SELECT auth.uid()) = user_id);
\n\nCREATE POLICY "Users can delete own session backups" ON public.interview_session_backups\n  FOR DELETE TO authenticated\n  USING ((SELECT auth.uid()) = user_id);
\n;
